// Safari Web Extension compatibility shim.
// Safari exposes the native WebExtension API as `browser`.
// This shim makes `chrome.*` an alias for `browser.*` so all existing
// chrome.* calls work transparently in Safari without any polyfill magic.
(function() {
    if (typeof browser !== 'undefined' && typeof chrome === 'undefined') {
        // Safari only has `browser` — expose it as `chrome`
        globalThis.chrome = browser;
    } else if (typeof chrome !== 'undefined' && typeof browser === 'undefined') {
        // Chrome only — expose chrome as browser for any browser.* calls
        globalThis.browser = chrome;
    }
    // If both exist (Safari 14+), they are independent native implementations.
    // Prefer browser.* for Safari-specific calls where needed.
})();
